1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_UNIT_PREMIUM = 25;
5	
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const FIRST_INSURANCE_RATE = 0.1;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_THRESHOLD_YEARS = 2;
12	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: COMPONENT_UNIT_PREMIUM,
20	  moonstone: COMPONENT_UNIT_PREMIUM,
21	};
22	
23	const INSURANCE_VALUES: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const DEDUCTIBLE = 100;
33	const CAP_MULTIPLIER = 2;
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	interface Item {
38	  type: string;
39	  material?: string;
40	  enchantment?: number;
41	  cursed?: boolean;
42	}
43	
44	interface QuoteStep {
45	  op: "quote";
46	  items: Item[];
47	}
48	
49	interface Damage {
50	  itemType: string;
51	  amount: number;
52	}
53	
54	interface ClaimStep {
55	  op: "claim";
56	  policy: number;
57	  incident: { cause?: string; damages: Damage[] };
58	}
59	
60	type Step = QuoteStep | ClaimStep;
61	
62	interface Scenario {
63	  customer: { yearsWithMHPCO: number };
64	  steps: Step[];
65	}
66	
67	interface PolicyState {
68	  items: Item[];
69	  insuranceSum: number;
70	  cap: number;
71	  remainingCap: number;
72	}
73	
74	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
75	const isMainItem = (item: Item): boolean => !isComponent(item);
76	
77	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
78	
79	const countsByType = (items: Item[]): Map<string, number> =>
80	  items.reduce((counts, item) => {
81	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
82	    return counts;
83	  }, new Map<string, number>());
84	
85	const componentGroupPremium = (count: number): number =>
86	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
87	
88	const sumComponentPremiums = (components: Item[]): number =>
89	  Array.from(countsByType(components).values()).reduce(
90	    (total, count) => total + componentGroupPremium(count),
91	    0,
92	  );
93	
94	const sumMainItemPremiums = (mainItems: Item[]): number =>
95	  mainItems.reduce((total, item) => total + basePremiumFor(item), 0);
96	
97	const policyBasePremium = (items: Item[]): number =>
98	  sumMainItemPremiums(items.filter(isMainItem)) +
99	  sumComponentPremiums(items.filter(isComponent));
100	
101	const itemModifierSurcharge = (item: Item): number => {
102	  if (isComponent(item)) return 0;
103	  const base = basePremiumFor(item);
104	  let surcharge = 0;
105	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
106	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_RATE;
107	  return surcharge;
108	};
109	
110	const sumItemModifiers = (items: Item[]): number =>
111	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
112	
113	interface CustomerContext {
114	  yearsWithMHPCO: number;
115	  isFollowUpContract: boolean;
116	}
117	
118	const policyModifierAmount = (policyBase: number, ctx: CustomerContext): number => {
119	  let amount = policyBase * FIRST_INSURANCE_RATE;
120	  if (ctx.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) amount -= policyBase * LOYALTY_DISCOUNT_RATE;
121	  if (ctx.isFollowUpContract) amount -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
122	  return amount;
123	};
124	
125	const computeQuote = (step: QuoteStep, ctx: CustomerContext) => {
126	  const policyBase = policyBasePremium(step.items);
127	  const itemSurcharges = sumItemModifiers(step.items);
128	  const policyMods = policyModifierAmount(policyBase, ctx);
129	  const premium = policyBase + itemSurcharges + policyMods + PROCESSING_FEE;
130	  return { premium: Math.ceil(premium) };
131	};
132	
133	const insuranceSumOf = (items: Item[]): number =>
134	  items.reduce((total, item) => total + (INSURANCE_VALUES[item.type] ?? 0), 0);
135	
136	const createPolicy = (items: Item[]): PolicyState => {
137	  const insuranceSum = insuranceSumOf(items);
138	  const cap = insuranceSum * CAP_MULTIPLIER;
139	  return { items, insuranceSum, cap, remainingCap: cap };
140	};
141	
142	const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
143	
144	const sumDamagePayouts = (damages: Damage[]): number =>
145	  damages.reduce((total, damage) => total + damagePayout(damage), 0);
146	
147	const processClaim = (step: ClaimStep, policy: PolicyState) => {
148	  const desired = sumDamagePayouts(step.incident.damages);
149	  const payout = Math.min(desired, policy.remainingCap);
150	  policy.remainingCap -= payout;
151	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
152	};
153	
154	interface ScenarioState {
155	  policies: PolicyState[];
156	  quoteCount: number;
157	  yearsWithMHPCO: number;
158	}
159	
160	const handleQuoteStep = (step: QuoteStep, state: ScenarioState) => {
161	  const ctx: CustomerContext = {
162	    yearsWithMHPCO: state.yearsWithMHPCO,
163	    isFollowUpContract: state.quoteCount > 0,
164	  };
165	  state.quoteCount += 1;
166	  state.policies.push(createPolicy(step.items));
167	  return computeQuote(step, ctx);
168	};
169	
170	const handleClaimStep = (step: ClaimStep, state: ScenarioState) =>
171	  processClaim(step, state.policies[step.policy]);
172	
173	export const runScenario = (input: unknown): unknown => {
174	  const scenario = input as Scenario;
175	  const state: ScenarioState = {
176	    policies: [],
177	    quoteCount: 0,
178	    yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
179	  };
180	  const results = scenario.steps.map((step) =>
181	    step.op === "quote" ? handleQuoteStep(step, state) : handleClaimStep(step, state),
182	  );
183	  return { results };
184	};
